sparql_query:
PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX cco: <https://www.commoncoreontologies.org/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?facility ?label
WHERE {
  VALUES ?beamline { <http://example.org/resource#beamline.001> }
  ?beamline a mds:Beamline .
  ?beamline cco:ont00001857 ?facility .
  ?facility a mds:SynchrotronFacility .
  OPTIONAL { ?facility rdfs:label ?label }
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?detector ?label
WHERE {
  VALUES ?recipe { <http://example.org/resource#recipe.001> }
  ?recipe a mds:XrayRecipe .
  ?tool obo:BFO_0000056 ?recipe .
  ?tool a mds:XrayDetector .
  BIND(?tool AS ?detector)
  OPTIONAL { ?detector rdfs:label ?label }
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX cco: <https://www.commoncoreontologies.org/>
SELECT ?pixelSizeWidth
WHERE {
  VALUES ?detector { <http://example.org/resource#detector.001> }
  ?detector a mds:XrayDetector .
  ?detector cco:ont00001904 ?pixelSizeWidth .
  ?pixelSizeWidth a mds:PixelSizeWidth .
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?method ?label
WHERE {
  VALUES ?sample { <http://example.org/resource#sample.001> }
  ?sample a mds:XraySample .
  ?method a mds:ProcessingMethod ;
          obo:BFO_0000057 ?sample .
  OPTIONAL { ?method rdfs:label ?label }
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX cco: <https://www.commoncoreontologies.org/>
SELECT ?formula
WHERE {
  VALUES ?sample { <http://example.org/resource#sample.001> }
  ?sample a mds:XraySample ;
          cco:ont00001879 ?formula .
  ?formula a mds:ChemicalFormula .
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX cco: <https://www.commoncoreontologies.org/>
SELECT ?latticeParam ?value
WHERE {
  VALUES ?pattern { <http://example.org/resource#pattern.001> }
  ?refinement a mds:RietveldRefinement ;
              cco:ont00001921 ?pattern ;
              cco:ont00001986 ?latticeParam .
  ?latticeParam a mds:LatticeParameter .
  OPTIONAL { ?latticeParam cco:ont00001769 ?value }
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX cco: <https://www.commoncoreontologies.org/>
SELECT ?dislocationDensity ?value
WHERE {
  VALUES ?pattern { <http://example.org/resource#pattern.001> }
  ?dlpa a mds:DiffractionLineProfileAnalysis ;
        cco:ont00001921 ?pattern ;
        cco:ont00001986 ?dislocationDensity .
  ?dislocationDensity a mds:DislocationDensity .
  OPTIONAL { ?dislocationDensity cco:ont00001769 ?value }
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX cco: <https://www.commoncoreontologies.org/>
SELECT ?phaseFraction ?value
WHERE {
  VALUES ?refinement { <http://example.org/resource#refinement.001> }
  ?refinement a mds:RietveldRefinement ;
              cco:ont00001986 ?phaseFraction .
  ?phaseFraction a mds:PhaseFraction .
  OPTIONAL { ?phaseFraction cco:ont00001769 ?value }
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX cco: <https://www.commoncoreontologies.org/>
SELECT ?transusTemp ?value
WHERE {
  VALUES ?sample { <http://example.org/resource#sample.001> }
  ?sample a mds:XraySample .
  ?transusTemp a mds:BetaTitaniumTransusTemperature ;
               obo:BFO_0000197 ?sample .
  OPTIONAL { ?transusTemp cco:ont00001769 ?value }
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?crystalStructure ?label
WHERE {
  ?phase a mds:AlphaTiPhase ;
         obo:BFO_0000171 ?unitCell .
  ?unitCell a mds:AlphaTiUnitCell ;
            obo:BFO_0000196 ?crystalStructure .
  ?crystalStructure a mds:CrystalStructure .
  OPTIONAL { ?crystalStructure rdfs:label ?label }
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX cco: <https://www.commoncoreontologies.org/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?morphology ?label
WHERE {
  ?solidification a mds:RapidSolidification ;
                  cco:ont00001986 ?morphology .
  ?morphology a/rdfs:subClassOf* mds:GrainMorphology .
  OPTIONAL { ?morphology rdfs:label ?label }
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX cco: <https://www.commoncoreontologies.org/>
SELECT ?thermalProfile
WHERE {
  VALUES ?ht { <http://example.org/resource#heattreatment.001> }
  ?ht a mds:IsothermalTransformation .
  ?directive cco:ont00001808 ?ht .
  ?directive a mds:ThermalProfile .
  BIND(?directive AS ?thermalProfile)
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX cco: <https://www.commoncoreontologies.org/>
SELECT ?coolingRate ?value
WHERE {
  VALUES ?cct { <http://example.org/resource#cct.001> }
  ?cct a mds:ContinuousCoolingTransformation .
  ?coolingRate a mds:CoolingRate ;
              obo:BFO_0000197 ?cct .
  OPTIONAL { ?coolingRate cco:ont00001769 ?value }
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX cco: <https://www.commoncoreontologies.org/>
SELECT ?config
WHERE {
  VALUES ?pattern { <http://example.org/resource#pattern1d.001> }
  ?integration a mds:AzimuthalIntegration ;
               cco:ont00001986 ?pattern ;
               cco:ont00001921 ?config .
  ?config a mds:IntegrationOptions .
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?transformation ?label
WHERE {
  ?transformation rdfs:subClassOf mds:SolidStatePhaseTransformation .
  OPTIONAL { ?transformation rdfs:label ?label }
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX cco: <https://www.commoncoreontologies.org/>
SELECT ?law ?label
WHERE {
  ?law rdfs:subClassOf mds:GoverningLaw ;
       rdfs:subClassOf [ a owl:Restriction ;
                         owl:onProperty cco:ont00001808 ;
                         owl:someValuesFrom mds:LatticeParameter ] .
  OPTIONAL { ?law rdfs:label ?label }
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT ?targetPhase ?label
WHERE {
  mds:BetaTiPhase rdfs:subClassOf [ a owl:Restriction ;
                                     owl:onProperty mds:transforms_into ;
                                     owl:someValuesFrom ?targetPhase ] .
  OPTIONAL { ?targetPhase rdfs:label ?label }
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX cco: <https://www.commoncoreontologies.org/>
SELECT ?holdTemp ?value
WHERE {
  VALUES ?experiment { <http://example.org/resource#isothermal.001> }
  ?experiment a mds:IsothermalTransformation .
  ?directive cco:ont00001808 ?experiment .
  ?directive cco:ont00001808 ?holdTemp .
  ?holdTemp a mds:IsothermalHoldTemperature .
  OPTIONAL { ?holdTemp cco:ont00001769 ?value }
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT ?amProcess ?amLabel ?solidification ?solidLabel
WHERE {
  ?amProcess rdfs:subClassOf mds:AdditiveManufacturingProcess .
  ?amProcess rdfs:subClassOf [ a owl:Restriction ;
                                owl:onProperty mds:has_increased_likelihood_of ;
                                owl:someValuesFrom ?solidification ] .
  ?solidification rdfs:subClassOf* mds:Solidification .
  OPTIONAL { ?amProcess rdfs:label ?amLabel }
  OPTIONAL { ?solidification rdfs:label ?solidLabel }
}
